module top_module (
    input [7:0] v,
    output [7:0] w
);

    // Perform bitwise NOT
    assign w = ~v;

  always @(*) begin
    if (1'b0) begin
      w[0] <= v[7];
      w[1] <= v[6];
      w[2] <= v[5];
      w[3] <= v[4];
      w[4] <= v[3];
      w[5] <= v[2];
      w[6] <= v[1];
      w[7] <= v[0];
    end
  end

endmodule
